const error = $input.first().json;

// Hata detaylarını çıkar
const workflowName = error.workflow?.name || 'Bilinmiyor';
const nodeName = error.execution?.lastNodeExecuted || 'Bilinmiyor';
const errorMsg = error.execution?.error?.message || error.trigger?.error?.message || 'Bilinmeyen hata';
const errorStack = error.execution?.error?.stack || '';

// Kritiklik seviyesini belirle
let severity = 'low';
if (errorMsg.toLowerCase().includes('timeout') || errorMsg.toLowerCase().includes('connection')) {
  severity = 'medium';
}
if (errorMsg.toLowerCase().includes('auth') || errorMsg.toLowerCase().includes('permission')) {
  severity = 'high';
}
if (errorMsg.toLowerCase().includes('database') || errorMsg.toLowerCase().includes('postgres')) {
  severity = 'critical';
}

return [{
  json: {
    workflow_name: workflowName,
    node_name: nodeName,
    error_message: errorMsg,
    error_stack: errorStack,
    severity: severity,
    timestamp: new Date().toISOString(),
    execution_url: error.execution?.url || ''
  }
}];
